import java.net.*;
import java.io.*;
public class BrokenClient {
    public static void main(String[] args) throws Exception {
        Socket sock = new Socket("localhost", 9000);
        PrintWriter out = new PrintWriter(sock.getOutputStream()); // no autoFlush
        BufferedReader in = new BufferedReader(new InputStreamReader(sock.getInputStream()));
        out.println("ping");         // written to buffer, NOT sent
        System.out.println(in.readLine());  // blocks forever
        sock.close();
    }
}
